# compute similarity scores against all quran verses using normalized char ratio and token-based F1
from difflib import SequenceMatcher

def char_ratio(a,b):
    return SequenceMatcher(None, a, b).ratio()

def token_f1(a,b):
    ta = set(a.split())
    tb = set(b.split())
    if not ta or not tb:
        return 0.0
    inter = ta & tb
    prec = len(inter) / len(tb)
    rec = len(inter) / len(ta)
    if prec+rec == 0:
        return 0.0
    return 2*prec*rec/(prec+rec)

